options.getOption:
const s = context.panel.data.series[0];
if (!s) { return {}; }
const f = s.fields;
const wd = f.find(x => x.name === 'weekday').values;
const hr = f.find(x => x.name === 'hour').values;
const eur = f.find(x => x.name === 'eur').values;
const days = ['Mon','Tue','Wed','Thu','Fri','Sat','Sun'];
const hours = Array.from({length:24}, (_,h) => String(h).padStart(2,'0'));
const data = [];
for (let i = 0; i < wd.length; i++) {
  const d = days.indexOf(String(wd[i]).slice(2));
  const h = hours.indexOf(String(hr[i]));
  if (d >= 0 && h >= 0) data.push([h, d, Number(Number(eur[i]).toFixed(3))]);
}
return {
  backgroundColor: 'transparent',
  tooltip: { position: 'top', formatter: p => days[p.value[1]] + ' ' + hours[p.value[0]] + ':00 — €' + p.value[2] + '/h' },
  grid: { left: 50, right: 70, top: 10, bottom: 40 },
  xAxis: { type: 'category', data: hours, name: 'hour', splitArea: { show: true } },
  yAxis: { type: 'category', data: days, inverse: true, splitArea: { show: true } },
  visualMap: { min: 0, max: 1, calculable: true, orient: 'vertical', right: 0, top: 'center', inRange: { color: ['#73bf69', '#fade2a', '#ff9830', '#f2495c'] } },
  series: [{ type: 'heatmap', data, emphasis: { itemStyle: { shadowBlur: 6 } } }]
};

const s = context.panel.data.series[0];
if (!s) { return {}; }
const f = s.fields.find(x => x.name === 'kW');
if (!f) { return {}; }
const kw = f.values;
const data = [];
for (let i = 0; i < kw.length; i++) {
  data.push([Number((i * 0.25).toFixed(2)), Number(Number(kw[i]).toFixed(3))]);
}
const totalH = Math.ceil(kw.length * 0.25);
return {
  backgroundColor: 'transparent',
  tooltip: { trigger: 'axis', formatter: p => { const q = Array.isArray(p) ? p[0] : p; return '≥ ' + q.value[1] + ' kW for ' + q.value[0] + ' h'; } },
  grid: { left: 60, right: 30, top: 25, bottom: 45 },
  xAxis: { type: 'value', name: 'hours at or above (h)', nameLocation: 'middle', nameGap: 30, min: 0, max: totalH },
  yAxis: { type: 'value', name: 'kW' },
  series: [{
    type: 'line', showSymbol: false, data,
    lineStyle: { width: 2, color: '#5794f2' },
    areaStyle: { opacity: 0.15, color: '#5794f2' },
    markLine: { symbol: 'none', lineStyle: { color: '#f2495c', type: 'dashed', width: 2 }, label: { formatter: '2.5 kW capacity floor' }, data: [{ yAxis: 2.5 }] }
  }]
};
